namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public int InstructorId { get; set; }
    public Instructor Instructor { get; set; } = new();
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string FullName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Za-z0-9\-]+$", ErrorMessage = "Student ID must contain only letters, numbers, and hyphens.")]
    [StringLength(20)]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CourseCatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CourseCatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 papers and holds 3 patents in neural network architectures.", Email = "achen@university.edu" },
            new() { Id = 2, Name = "Dr. Robert Kim", Title = "Associate Professor", Bio = "Dr. Kim's research focuses on distributed systems and cloud computing. He previously worked at a major tech company for 10 years.", Email = "rkim@university.edu" },
            new() { Id = 3, Name = "Dr. Sarah Patel", Title = "Professor", Bio = "Dr. Patel is a leading researcher in abstract algebra with a focus on group theory and its applications to cryptography.", Email = "spatel@university.edu" },
            new() { Id = 4, Name = "Dr. James O'Brien", Title = "Assistant Professor", Bio = "Dr. O'Brien studies probability theory and stochastic processes with applications in financial mathematics.", Email = "jobrien@university.edu" },
            new() { Id = 5, Name = "Dr. Maria Garcia", Title = "Professor", Bio = "Dr. Garcia is an experimental physicist specializing in quantum optics. She leads the university's photonics laboratory.", Email = "mgarcia@university.edu" },
            new() { Id = 6, Name = "Dr. William Torres", Title = "Associate Professor", Bio = "Dr. Torres researches classical mechanics and astrophysics. He is the author of a widely used introductory physics textbook.", Email = "wtorres@university.edu" },
            new() { Id = 7, Name = "Prof. Emily Hart", Title = "Professor", Bio = "Prof. Hart is an award-winning author and literary critic specializing in 19th-century American literature.", Email = "ehart@university.edu" },
            new() { Id = 8, Name = "Dr. David Nguyen", Title = "Assistant Professor", Bio = "Dr. Nguyen's research examines the social and political history of East Asia in the modern era.", Email = "dnguyen@university.edu" },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, data structures, and basic algorithms. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, DepartmentName = "Computer Science", InstructorId = 2, Instructor = _instructors[1], IsFeatured = true },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs, hash tables) and algorithm design techniques (divide-and-conquer, dynamic programming, greedy algorithms). Prerequisite: CS 101.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", DepartmentId = 1, DepartmentName = "Computer Science", InstructorId = 2, Instructor = _instructors[1] },
            new() { Id = 3, Code = "CS 310", Title = "Artificial Intelligence", Description = "Foundations of artificial intelligence including search algorithms, knowledge representation, machine learning basics, and neural networks. Prerequisite: CS 201.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", DepartmentId = 1, DepartmentName = "Computer Science", InstructorId = 1, Instructor = _instructors[0], IsFeatured = true },
            new() { Id = 4, Code = "CS 350", Title = "Software Engineering", Description = "Principles and practices of software engineering including requirements analysis, design patterns, testing strategies, and agile methodologies.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", DepartmentId = 1, DepartmentName = "Computer Science", InstructorId = 1, Instructor = _instructors[0] },
            new() { Id = 5, Code = "MATH 101", Title = "Calculus I", Description = "Introduction to differential calculus: limits, continuity, derivatives, and applications. Covers techniques of differentiation and introductory integration.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 2, DepartmentName = "Mathematics", InstructorId = 4, Instructor = _instructors[3], IsFeatured = true },
            new() { Id = 6, Code = "MATH 201", Title = "Linear Algebra", Description = "Study of vector spaces, linear transformations, matrices, determinants, eigenvalues, and inner product spaces.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", DepartmentId = 2, DepartmentName = "Mathematics", InstructorId = 3, Instructor = _instructors[2] },
            new() { Id = 7, Code = "MATH 301", Title = "Abstract Algebra", Description = "Introduction to algebraic structures: groups, rings, and fields. Covers homomorphisms, quotient structures, and applications to coding theory.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:15 PM", DepartmentId = 2, DepartmentName = "Mathematics", InstructorId = 3, Instructor = _instructors[2] },
            new() { Id = 8, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Covers Newton's laws, energy conservation, rotational motion, oscillations, and introductory thermodynamics.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 3, DepartmentName = "Physics", InstructorId = 6, Instructor = _instructors[5] },
            new() { Id = 9, Code = "PHYS 220", Title = "Quantum Mechanics", Description = "Introduction to quantum theory: wave-particle duality, Schrödinger equation, quantum states, measurement, and applications to atomic physics.", Credits = 3, Schedule = "Tue/Thu 2:00–3:15 PM", DepartmentId = 3, DepartmentName = "Physics", InstructorId = 5, Instructor = _instructors[4], IsFeatured = true },
            new() { Id = 10, Code = "ENG 101", Title = "College Writing", Description = "Develop critical reading and academic writing skills. Emphasis on argumentation, research methods, and clear prose style.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 4, DepartmentName = "English", InstructorId = 7, Instructor = _instructors[6] },
            new() { Id = 11, Code = "ENG 250", Title = "American Literature", Description = "Survey of major works in American literature from the colonial period to the present, with attention to historical and cultural contexts.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", DepartmentId = 4, DepartmentName = "English", InstructorId = 7, Instructor = _instructors[6] },
            new() { Id = 12, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of world civilizations from prehistory to 1500 CE. Examines political, social, economic, and cultural developments across regions.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", DepartmentId = 5, DepartmentName = "History", InstructorId = 8, Instructor = _instructors[7] },
            new() { Id = 13, Code = "HIST 205", Title = "Modern East Asian History", Description = "Political, social, and cultural history of China, Japan, and Korea from the 19th century to the present.", Credits = 3, Schedule = "Tue/Thu 3:30–4:45 PM", DepartmentId = 5, DepartmentName = "History", InstructorId = 8, Instructor = _instructors[7], IsFeatured = true },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public void SubmitEnrollment(EnrollmentRequest request) => _enrollments.Add(request);
}

