@page "/"

<PageTitle>Home — University Course Catalog</PageTitle>

@inject CourseCatalogService CatalogService

<h1>Welcome to the University Course Catalog</h1>
<p class="lead">Browse our departments and courses, and submit your enrollment request online.</p>

<h2 class="mt-4">Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
