@page "/"

<PageTitle>Home — University Course Catalog</PageTitle>

@inject CourseCatalogService CatalogService

<h1>Welcome to the University Course Catalog</h1>
<p class="lead">Browse our departments and courses, and submit your enrollment request online.</p>

<h2 class="mt-4">Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.Code — @course.Title</h5>
                    <p class="card-text text-muted">@course.DepartmentName · @course.Credits credits</p>
                    <p class="card-text">@Truncate(course.Description, 120)</p>
                </div>
                <div class="card-footer bg-transparent">
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-5">Departments</h2>
<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name</h5>
                    <p class="card-text">@dept.Description</p>
                </div>
                <div class="card-footer bg-transparent">
                    <a href="courses?departmentId=@dept.Id" class="btn btn-outline-primary btn-sm">Browse Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

toolArgs.file_text:
@page "/departments"

<PageTitle>Departments — University Course Catalog</PageTitle>

@inject CourseCatalogService CatalogService

<h1>Departments</h1>

<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-6 mb-4">
            <div class="card h-100">
                <div class="card-body">
                    <h4 class="card-title">@dept.Code — @dept.Name</h4>
                    <p class="card-text">@dept.Description</p>
                </div>
                <div class="card-footer bg-transparent">
                    <a href="courses?departmentId=@dept.Id" class="btn btn-primary">Browse Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
    }
}

@page "/enroll"

<PageTitle>Enroll — University Course Catalog</PageTitle>

@inject CourseCatalogService CatalogService

<h1>Enrollment Request</h1>
<p>Fill out the form below to request enrollment in a course.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Request submitted!</strong> Your enrollment request for
        <em>@selectedCourseTitle</em> has been received. You will be contacted at your university email.
    </div>
    <a href="enroll" class="btn btn-primary">Submit Another Request</a>
}
else
{
    <EditForm Model="model" FormName="enrollment" OnValidSubmit="HandleSubmit" method="post" class="mt-3" style="max-width: 600px;">
        <AntiforgeryToken />
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="fullName" class="form-label">Full Name</label>
            <InputText id="fullName" @bind-Value="model.FullName" class="form-control" />
            <ValidationMessage For="() => model.FullName" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" @bind-Value="model.StudentId" class="form-control" placeholder="e.g. STU-12345" />
            <ValidationMessage For="() => model.StudentId" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" @bind-Value="model.CourseId" class="form-select">
                <option value="0">— Select a course —</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id">@course.Code — @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.CourseId" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm] private EnrollmentRequest model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;
    private string selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();

        if (CourseId.HasValue && model.CourseId == 0)
            model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourse(model.CourseId);
        selectedCourseTitle = course is not null ? $"{course.Code} — {course.Title}" : "Unknown";
        CatalogService.SubmitEnrollment(model);
        submitted = true;
    }
}

